.darma-loader-uiverse-triad-preloader-shadow { display: inline-flex; align-items: center; justify-content: center; position: relative; }
.darma-loader-uiverse-triad-preloader-shadow__container {
  position: relative;
}

.darma-loader-uiverse-triad-preloader-shadow__container .darma-loader-uiverse-triad-preloader-shadow__preloader {
animation: darma-loader-uiverse-triad-preloader-darma-loader-uiverse-triad-preloader-shadow-shadow-rotate 2.3s cubic-bezier(0.75, 0, 0.5, 1) infinite;
}

@keyframes darma-loader-uiverse-triad-preloader-shadow-rotate {
50% {
transform: rotate(360deg);
}

100% {
transform: rotate(720deg);
}
}

.darma-loader-uiverse-triad-preloader-shadow__preloader span {
--c: var(--loader-color, #f23f3f);
position: absolute;
display: block;
height: 64px;
width: 64px;
background: var(--c);
border: 1px solid var(--c);
border-radius: 100%;
}

.darma-loader-uiverse-triad-preloader-shadow__preloader span:nth-child(1) {
transform: translate(-28px, -28px);
animation: darma-loader-uiverse-triad-preloader-darma-loader-uiverse-triad-preloader-shadow-shadow-shape_1 2.3s cubic-bezier(0.75, 0, 0.5, 1) infinite;
}

@keyframes darma-loader-uiverse-triad-preloader-shadow-shape_1 {
60% {
transform: scale(0.4);
}
}

.darma-loader-uiverse-triad-preloader-shadow__preloader span:nth-child(2) {
transform: translate(28px, -28px);
animation: darma-loader-uiverse-triad-preloader-darma-loader-uiverse-triad-preloader-shadow-shadow-shape_2 2.3s cubic-bezier(0.75, 0, 0.5, 1) infinite;
}

@keyframes darma-loader-uiverse-triad-preloader-shadow-shape_2 {
40% {
transform: scale(0.4);
}
}

.darma-loader-uiverse-triad-preloader-shadow__preloader span:nth-child(3) {
position: relative;
border-radius: 0px;
transform: scale(0.98) rotate(-45deg);
animation: darma-loader-uiverse-triad-preloader-darma-loader-uiverse-triad-preloader-shadow-shadow-shape_3 2.3s cubic-bezier(0.75, 0, 0.5, 1) infinite;
}

@keyframes darma-loader-uiverse-triad-preloader-shadow-shape_3 {
50% {
border-radius: 100%;
transform: scale(0.5) rotate(-45deg);
}

100% {
transform: scale(0.98) rotate(-45deg);
}
}

.darma-loader-uiverse-triad-preloader-shadow__shadow {
position: relative;
top: 30px;
left: 50%;
transform: translateX(-50%);
display: block;
height: 16px;
width: 64px;
border-radius: 50%;
background-color: #d9d9d9;
border: 1px solid #d9d9d9;
animation: darma-loader-uiverse-triad-preloader-shadow-shadow 2.3s cubic-bezier(0.75, 0, 0.5, 1) infinite;
}

@keyframes darma-loader-uiverse-triad-preloader-shadow-shadow {
50% {
transform: translateX(-50%) scale(0.5);
border-color: #f2f2f2;
}
}

